// GET /api/member/contributions/:id
router.get('/:id', contributionIdParamRules, validate, getMyContributionById)

// GET /api/member/contributions/year/:year
router.get('/year/:year', yearParamRules, validate, getMyContributionsByYear)

module.exports = router
